// 1. 取得相關節點的資料
const routerOutput = $('ambiguity_router').item.json.output;
const intentIdentificationOutput = $('intent_identification').item.json.output;

// 2. 預先處理意圖清單（轉換成字串陣列）
const intentNames = intentIdentificationOutput.map(item => item.intent);

// 3. 計算 callType
let callType;
if (routerOutput.selected_intent === 'positive') {
    // 如果是 positive，抓取意圖辨識清單的第一個元素
    callType = intentNames[0];
} else {
    // 否則直接使用選中的意圖 (如 negative, other)
    callType = routerOutput.selected_intent;
}

// 4. 計算 callType_index
// 注意：如果 callType 是 'negative' 且不在 intentNames 中，結果會是 -1
const callType_index = intentNames.indexOf(callType);

// 5. 回傳結果給下一個節點
return {
  callType: callType,
  callType_index: callType_index
};
